" async for event in self.orchestrator.stream(message): if event.type == "llm_token": yield f"data: {json.dumps({'type': 'token', 'content': event.token})}

" elif event.type == "tool_call": yield f"data: {json.dumps({'type': 'tool', 'name': event.tool_name})}

" elif event.type == "done": yield f"data: {json.dumps({'type': 'done'})}

" 事件类型设计 事件 说明 前端处理 start 会话开始 显示加载指示器 token LLM 输出的 token 流 打字机效果追加文字 thinking Agent 的思考过程（可选） 折叠显示 tool_start / tool_end 工具调用的开始/结果 进度指示 error 错误信息 错误提示 + 重试按钮 done 完成 隐藏加载指示器 模式三：异步任务 + 回调（长任务） 适合代码生成、数据分析等耗时长的任务。提交任务后立即返回 task_id，通过轮询或 WebSocket 获取结果。 @app.post("/task/submit") async def submit_task(request: TaskRequest): task_id = uuid4() background_tasks.add_task(run_agent_task, task_id, request) return {"task_id": task_id, "status": "pending"} @app.get("/task/{task_id}/status") async def task_status(task_id: str): return task_store.get(task_id) 会话管理 Agent 的会话管理与传统 Web 有本质区别——会话中不仅有对话历史，还有工具调用状态、上下文压缩、工作记忆。 class SessionManager: def __init__(self, redis: Redis, db: Database): self.redis = redis # 热会话（最近 30min 活跃的） self.db = db # 冷会话持久化 async def get_or_create(self, user_id, session_id): # 1. 先从 Redis 取（热数据） session = await self.redis.get(f"session:{session_id}") if session: return Session.from_json(session) # 2. Redis 没有，从 DB 加载 row = await self.db.fetch_one( "SELECT * FROM sessions WHERE id=$1 AND user_id=$2", session_id, user_id ) # 3. 恢复到 Redis await self.cache_session(session) return session 数据库设计（核心表） -- 用户表 CREATE TABLE users ( id UUID PRIMARY KEY, api_key_hash TEXT NOT NULL, quota_limit INT DEFAULT 1000 ); -- 会话表 CREATE TABLE sessions ( id UUID PRIMARY KEY, user_id UUID REFERENCES users(id), title TEXT, messages JSONB DEFAULT '[]', summary TEXT, token_count INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW() ); -- 工具调用日志（可观测性） CREATE TABLE tool_call_logs ( id BIGSERIAL PRIMARY KEY, session_id UUID, tool_name TEXT, args JSONB, result JSONB, duration_ms INT, error TEXT, created_at TIMESTAMPTZ DEFAULT NOW() ); CREATE INDEX idx_tool_logs_session ON tool_call_logs(session_id); 安全清单 所有 API 端点需要 JWT 或 API Key 认证 用户数据隔离：session_id/user_id 必须关联校验，防止越权访问 输入长度限制：message 长度上限（如 8000 字符），防止 Token 滥用 速率限制：每用户每分钟最多 N 次 LLM 调用 工具白名单：生产环境只注册安全审计过的工具 Prompt 注入检测：用正则或分类器检测恶意 Prompt 模式 部署架构 FastAPI + Uvicorn ：最主流，异步支持好，SSE 原生支持 Nginx 反向代理 ：SSL 终结、负载均衡、SSE 需要禁用缓冲 Docker + HealthCheck ：容器化部署，健康检查端点 /health Graceful Shutdown ：收到 SIGTERM 后完成当前请求再退出 ← 返回首页
